# Module: GraphOps.psm1
# Purpose: Common Graph operations for Intune and Entra ID management

function Connect-GraphSession {
    param([string]$TenantId, [string]$ClientId, [string]$ClientSecret)
    $body = @{ grant_type='client_credentials'; client_id=$ClientId;
               client_secret=$ClientSecret; scope='https://graph.microsoft.com/.default' }
    $token = Invoke-RestMethod -Uri "https://login.microsoftonline.com/$TenantId/oauth2/v2.0/token" -Method Post -Body $body
    $global:GraphToken = $token.access_token
}

function Get-StaleDevices {
    $headers = @{ Authorization = "Bearer $global:GraphToken" }
    $url = 'https://graph.microsoft.com/v1.0/deviceManagement/managedDevices'
    $result = Invoke-RestMethod -Uri $url -Headers $headers
    $cutoff = (Get-Date).AddDays(-7)
    $result.value | Where-Object { [datetime]$_.lastSyncDateTime -lt $cutoff }
}

