    param([string]$UserId, [string]$GroupId)
    $headers = @{ Authorization = "Bearer $global:GraphToken"; 'Content-Type'='application/json' }
    $body = @{ '@odata.id' = "https://graph.microsoft.com/v1.0/directoryObjects/$UserId" } | ConvertTo-Json
    Invoke-RestMethod -Uri "https://graph.microsoft.com/v1.0/groups/$GroupId/members/`$ref" -Method Post -Headers $headers -Body $body
}

