    param([string]$UserId, [string]$GroupId)
    $headers = @{ Authorization = "Bearer $global:GraphToken" }
    Invoke-RestMethod -Uri "https://graph.microsoft.com/v1.0/groups/$GroupId/members/$UserId/`$ref" -Method Delete -Headers $headers
}

